object NetworkModule {

    private const val BASE_URL_DEV = "https://api.dev.example.com/"
    private const val BASE_URL_STAGING = "https://api.staging.example.com/"
    private const val BASE_URL_PRODUCTION = "https://api.example.com/"

    fun createRetrofitInstance(environment: Environment): Retrofit {
        val okHttpClient = provideOkHttpClient(environment)
        return Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }

    private fun getBaseUrl(environment: Environment): String {
        return when (environment) {
            Environment.DEV -> BASE_URL_DEV
            Environment.STAGING -> BASE_URL_STAGING
            Environment.PRODUCTION -> BASE_URL_PRODUCTION
        }
    }

    private fun provideOkHttpClient(environment: Environment): OkHttpClient {
        val loggingInterceptor = HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.BODY }

        return OkHttpClient.Builder()
            .addInterceptor(loggingInterceptor)
            .authenticator { route, response ->
                if (response.request.header("Authorization") != null) {
